<?php
// GLV Deploy Script — subir a public_html y abrir en el navegador
$files = [
  'index.html' => '',
  'huevo-proteinas.html' => '',
  'coco-aceites.html' => '',
  'granos-cereales.html' => '',
  'comercio-internacional.html' => '',
  'animales-vivos.html' => '',
  'frutas.html' => '',
  'send-email.php' => '',
];

$base = __DIR__;
$ok = []; $fail = [];
foreach($files as $name => $b64){
  $content = gzdecode(base64_decode($b64));
  $path = $base . "/" . $name;
  if(file_put_contents($path, $content) !== false) $ok[] = $name;
  else $fail[] = $name;
}
echo "<h2>GLV Deploy</h2>";
echo "<p style=color:green>OK: " . implode(", ", $ok) . "</p>";
if($fail) echo "<p style=color:red>FAIL: " . implode(", ", $fail) . "</p>";
echo "<p><a href=./index.html>Abrir sitio</a></p>";
// Eliminar este script despues de ejecutar
unlink(__FILE__);
echo "<p>Script eliminado.</p>";
?>